import{_ as n,C as o,o as l,c as s,E as a,w as r,a as i,a0 as d}from"./chunks/framework.CkNTPv-z.js";const p=JSON.parse('{"title":"Moving to Hungary","description":"Immigration pathways and relocation guide for Hungary","frontmatter":{"layout":"doc","title":"Moving to Hungary","description":"Immigration pathways and relocation guide for Hungary"},"headers":[],"relativePath":"europe/hungary/moving-there.md","filePath":"europe/hungary/moving-there.md","lastUpdated":null}'),g={name:"europe/hungary/moving-there.md"};function h(u,t,c,m,f,y){const e=o("Badge");return l(),s("div",null,[a(e,{variant:"green"},{default:r(()=>[...t[0]||(t[0]=[i("EU: Free Movement",-1)])]),_:1}),a(e,{variant:"yellow"},{default:r(()=>[...t[1]||(t[1]=[i("Non-EU: Work Visa",-1)])]),_:1}),a(e,{variant:"yellow"},{default:r(()=>[...t[2]||(t[2]=[i("No Specific DN Visa",-1)])]),_:1}),t[3]||(t[3]=d('<h1 id="moving-to-hungary" tabindex="-1">Moving to Hungary <a class="header-anchor" href="#moving-to-hungary" aria-label="Permalink to &quot;Moving to Hungary&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eea-eu-citizens" tabindex="-1">EEA/EU Citizens <a class="header-anchor" href="#eea-eu-citizens" aria-label="Permalink to &quot;EEA/EU Citizens&quot;">​</a></h3><ul><li><strong>Free movement rights</strong> — no visa required</li><li><strong>Up to 3 months</strong>: No registration needed</li><li><strong>Over 3 months</strong>: Register with the Immigration Office (Országos Idegenrendészeti Főigazgatóság)</li><li><strong>Right to work</strong>: Automatic</li><li><strong>Residence card</strong>: Required for stays over 3 months</li></ul><h3 id="uk-citizens-post-brexit" tabindex="-1">UK Citizens (Post-Brexit) <a class="header-anchor" href="#uk-citizens-post-brexit" aria-label="Permalink to &quot;UK Citizens (Post-Brexit)&quot;">​</a></h3><ul><li><strong>Schengen Area</strong>: Visa-free for up to 90 days in any 180-day period</li><li><strong>Long-term residency</strong>: Requires a residence permit: <ul><li>Work permit (job offer from Hungarian employer)</li><li>Student visa (enrollment at Hungarian university)</li><li>Family reunification</li><li>White Card (remote work visa)</li></ul></li></ul><h3 id="third-country-nationals" tabindex="-1">Third-Country Nationals <a class="header-anchor" href="#third-country-nationals" aria-label="Permalink to &quot;Third-Country Nationals&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Work Permit</td><td>Job offer from Hungarian employer</td><td>Up to 2 years, renewable</td></tr><tr><td>Student Visa</td><td>Enrollment at accredited institution</td><td>Duration of studies</td></tr><tr><td>Family Reunification</td><td>Family ties to Hungarian resident</td><td>Tied to sponsor&#39;s status</td></tr><tr><td>EU Blue Card</td><td>Highly skilled (salary ~€35,000+/year)</td><td>Up to 4 years</td></tr><tr><td>White Card</td><td>Remote work for foreign company</td><td>Up to 1 year, renewable</td></tr></tbody></table><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>Hungary offers a <strong>White Card</strong> for digital nomads:</p><ul><li>For remote employees of non-Hungarian companies</li><li>Valid for up to <strong>1 year</strong>, renewable once</li><li>Requirements: Remote employment, income above threshold</li><li>Also available for freelancers with foreign clients</li></ul><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] <strong>Passport</strong>: Valid for duration of stay</li><li>[ ] <strong>Visa</strong>: Apply 2-3 months in advance (non-EU)</li><li>[ ] <strong>Healthcare</strong>: Private health insurance initially; register with NEAK after residency</li><li>[ ] <strong>HRT</strong>: Get 6-month supply and doctor&#39;s letter (translated to Hungarian)</li><li>[ ] <strong>Banking</strong>: Consider OTP Bank, K&amp;H, or Revolut</li><li>[ ] <strong>Housing</strong>: Research rental market (ingatlan.com, alberlet.hu)</li><li>[ ] <strong>Language</strong>: Hungarian essential for daily life and bureaucracy</li><li>[ ] <strong>Document translation</strong>: Official Hungarian translations needed</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] Register with Immigration Office (non-EU) or municipality (EU)</li><li>[ ] Obtain Hungarian address card (lakcímkártya)</li><li>[ ] Obtain TAJ number (health insurance card)</li><li>[ ] Register with NEAK (National Health Insurance Fund)</li><li>[ ] Open local bank account</li><li>[ ] Get local SIM card (Telekom, Vodafone, Yettel)</li><li>[ ] Connect with LGBTQ+ community (Háttér Society, Transvanilla)</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><ul><li><strong>Moderate</strong> — mid-range EU costs</li><li>Monthly rent (1-bed): €400-800 (Budapest), €300-500 (Debrecen), €250-400 (Pécs)</li><li>Monthly groceries: €250-350</li><li>Public transport: €30/month (Budapest)</li><li>Dining out: €8-15 per meal</li></ul><h3 id="best-cities" tabindex="-1">Best Cities <a class="header-anchor" href="#best-cities" aria-label="Permalink to &quot;Best Cities&quot;">​</a></h3><table tabindex="0"><thead><tr><th>City</th><th>LGBTQ+ Scene</th><th>Trans Healthcare</th></tr></thead><tbody><tr><td><strong>Budapest</strong></td><td>Moderate but under pressure</td><td>Only real option</td></tr><tr><td><strong>Debrecen</strong></td><td>Very limited</td><td>None</td></tr><tr><td><strong>Szeged</strong></td><td>Very limited</td><td>None</td></tr></tbody></table><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><ul><li><strong>Winters</strong>: Cold (-5°C to 5°C), snow common</li><li><strong>Summers</strong>: Warm to hot (25-35°C)</li><li><strong>Best time to arrive</strong>: Spring or early autumn</li></ul><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><ul><li>Official language: Hungarian (Uralic, unrelated to neighboring languages)</li><li>English: Moderate in Budapest, limited elsewhere</li><li>German: Somewhat understood in western areas</li><li>Hungarian is very challenging to learn and essential for bureaucracy</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://oif.gov.hu/" target="_blank" rel="noreferrer">Immigration Office (Országos Idegenrendészeti Főigazgatóság)</a></li><li><a href="https://neak.gov.hu/" target="_blank" rel="noreferrer">NEAK (National Health Insurance Fund)</a></li><li><a href="https://en.hatter.hu/" target="_blank" rel="noreferrer">Háttér Society</a></li><li><a href="https://transvanilla.hu/" target="_blank" rel="noreferrer">Transvanilla Transgender Association</a></li><li><a href="https://ingatlan.com/" target="_blank" rel="noreferrer">Ingatlan.com (housing)</a></li></ul>',27))])}const v=n(g,[["render",h]]);export{p as __pageData,v as default};
